Armas
INSERT INTO Armas (nombre, afinidad, descripcion, obtencion) VALUES
('Caminador de Fuego', 'Cantidad, Daño, Duración, Tamaño, Velocidad de Ataque', 'Deja un rastro de fuego a tu paso', 'La tienes de inicio, ya está desbloqueada'), -- [cite: 9, 10, 11, 12]
('Espada', 'Cantidad, Daño, Retroceso, Tamaño, Velocidad de Ataque', 'Corta a través de múltiples enemigos', 'La tienes de inicio, ya está desbloqueada'), -- [cite: 14, 15, 16, 17]
('Bastón de Rayo', 'Cantidad, Daño, Rebote de Proyectiles, Tamaño, Velocidad de Ataque', 'Invoca rayos para fulminar a los enemigos cercanos', 'La tienes de inicio, ya está desbloqueada'), -- [cite: 19, 20, 21, 22]
('Bastón de Fuego', 'Cantidad, Daño, Tamaño, Velocidad de Ataque, Velocidad de Proyectil', 'Dispara bolas de fuego que explotan al impactar', 'La tienes de inicio, ya está desbloqueada'), -- [cite: 24, 25, 26, 27]
('Chunkers', 'Cantidad, Daño, Retroceso, Tamaño, Velocidad de Ataque, Velocidad de Proyectil', 'Invoca rocas gordas que giran a tu alrededor', 'La tienes de inicio, ya está desbloqueada'), -- [cite: 29, 30, 31, 32]
('Hueso', 'Cantidad, Daño, Daño Crítico, Probabilidad de Crítico, Rebote de Proyectiles, Velocidad de Ataque, Velocidad de proyectiles', 'Lanza huesos que rebotan en los enemigos', 'La tienes de inicio, ya está desbloqueada'), -- [cite: 34, 35, 36, 37]
('Arco', 'Cantidad, Daño, Daño Crítico, Probabilidad de Crítico, Tamaño, Velocidad de Ataque, Velocidad de Proyectil', 'Dispara flechas que atraviesan enemigos', 'La tienes de inicio, ya está desbloqueada'), -- [cite: 39, 40, 41, 42]
('Revólver', 'Cantidad, Daño, Daño Crítico, Probabilidad de Crítica, Rebote de Proyectil, Velocidad de Ataque, Velocidad de Proyectil', 'Dispara múltiples balas a los enemigos.', 'Mata a 7500 enemigos'), -- [cite: 44, 45, 46, 47]
('Aegis', 'Cantidad, Daño, Retroceso, Tamaño, Velocidad de Ataque', 'Bloquea ataques y lanza ondas de choque', 'Bloquea 500 de daño con Armadura de Sir Oofie'), -- [cite: 49, 50, 51, 52]
('Aura', 'Daño, Tamaño, Velocidad de Ataque', 'Daña los enemigos a tu alrededor', 'No recibas daño por 2 minutos'), -- [cite: 54, 55, 56, 57]
('Hacha', 'Cantidad, Daño, Duración, Tamaño, Velocidad de Ataque', 'Lanza hachas giratorias que hacen daño en área', 'Mata a 2000 enemigos usando la espada'), -- [cite: 59, 60, 61, 62]
('Bananarang', 'Cantidad, Daño, Tamaño, Velocidad de Ataque, Velocidad de proyectiles', 'Lanza bananas que regresan a ti', 'Encuentra la Banana oculta'), -- [cite: 64, 65, 66, 67]
('Minas', 'Cantidad, Daño, Duracion, Velocidad de ataque', 'Coloca minas a tu alrededor que explotan cuando los enemigos se acercan', 'Mata 7500 enemigos con Cohete Suelto'), -- [cite: 69, 70, 71, 72]
('Fideo Espacial', 'Daño, Duaracion, Tamaño, Velocidad de ataque', 'Se adhiere a un enemigo cercano. Daño a los enemigos en el camino', 'Completa Desierto nivel 2 como Tony McVeloz'), -- [cite: 74, 75, 76, 77]
('Rifle de Francotirador', 'Cantidad, Daño, Tamaño, Velocidad de Ataque', 'Dispara balas perforantes. Se puede apuntar manualmente', 'Lleva el tomo de Precisión a nivel 10'), -- [cite: 79, 80, 81, 82]
('Cohete Suelto', 'Cantidad, Daño, Probabilidad de Crítico, Velocidad de Ataque, Velocidad de Proyectil', 'Lanza misiles teledirigidos', 'Mata a 15000 enemigos como Cl4nk'), -- [cite: 84, 85, 86, 87]
('Escopeta Suelta', 'Cantidad, Daño, Daño Crítico, Probabilidad de Crítico, Tamaño, Velocidad de ataque', 'Dispara en abanico, más fuerte de cerca. Puede apuntarse manualmente', '5% de probabilidad de encontrar al romper una Tumbleweed en Desierto Etapa 2.'), -- [cite: 89, 90, 91, 92]
('Daga Inalámbrica', 'Cantidad, Daño, Rebote de Proyectil, Velocidad de Ataque, Velocidad de Proyectil', 'Lanza dagas inteligentes a tus enemigos, ¡La tecnología sin cables está desatada!', 'Lleva el Bastón del Rayo a nivel 15'), -- [cite: 94, 95, 96, 97]
('Caminante de Escarcha', 'Daño, Duración, Tamaño, Velocidad de ataque', 'Congela y daña enemigos a tu alrededor', 'Congela 1000 enemigos con el Cubo de Hielo'), -- [cite: 99, 100, 101, 102]
('Tornado', 'Cantidad, Daño, Retroceso, Tamaño, Velocidad de Ataque, Velocidad de Proyectil', 'Envía tornados que derriban a los enemigos', 'Recarga un santuario de carga de energía durante una Tormenta de arena en el Desierto'), -- [cite: 104, 105, 106, 107]
('Dexecutioner', 'Cantidad, Daño, Probabilidad de Crítico, Tamaño, Velocidad de Ataque', 'Cuchilla perforante . Pequeña chance de ejecutar instantáneamente a un enemigo', 'Mata 12500 enemigos usando la Espada'), -- [cite: 109, 110, 111, 112]
('Magia Sangrienta', 'Cantidad, Daño, Tamaño, Velocidad de Ataque', 'Invoca magia de sangre. 5% de probabilidad de aumentar tu vida máxima al derrotar enemigos', 'Lleva el tomo Sangriento a nivel 12'), -- [cite: 114, 115, 116, 117]
('Agujero Negro', 'Cantidad, Daño, Duración, Tamaño, Velocidad de Ataque', 'Dispara un agujero negro que atrae a los enemigos', 'Lleva el tomo de Empuje a nivel 10'), -- [cite: 119, 120, 121, 122]
('Frasco Venenoso', 'Cantidad, Daño, Duración, Tamaño, Velocidad de Ataque, Velocidad de Proyectil', '  Lanza frascos tóxicos a tus enemigos, causando daño en área y envenenándolos', 'Mata a Gran Escorpión (minijefe) en Desierto 3 veces'), -- [cite: 124, 125, 126, 127]
('Katana', 'Cantidad, Daño, Daño Crítico, Probabilidad de Crítico, Tamaño, Velocidad de Ataque', 'Un filo afilado que busca al enemigo más cercano', '5% de probabilidad de encontrar al romper una Tumbleweed en Desierto Etapa 1'), -- [cite: 129, 130, 131, 132]
('Aliento de Dragón', 'Daño, Duración, Tamaño, Velocidad de ataque', 'Lanza un feroz aliento de dragón en cono hacia los enemigos cercanos', 'Mata 1000 Espectros como Zorro en Desierto'), -- [cite: 134, 135, 136, 137]
('Dado', 'Cantidad, Daño, Daño Crítico , Probabilidad de Crítico, Tamaño, Velocidad de Ataque, Velocidad de Proyectil', 'Lanza un dado que hace 1-6 de daño. Con un 6 aumenta para siempre el Crit Chance del arma', 'Lleva el tomo de Suerte a nivel 12'), -- [cite: 139, 140, 141, 142]
('Espada Heroica', 'Cantidad de Proyectiles, Daño, Tamaño, Velocidad de Ataque, Velocidad de Proyectil', 'Atraviesa varios enemigos y lanza un proyectil cortante', 'Derrota a un jefe de etapa sin agarrar objetos, sin power-up y sin usar santuarios'), -- [cite: 144, 145, 146, 147]
('Espada Corrupta', 'Cantidad de Proyectil, Daño, Tamaño, Velocidad de Ataque, Velocidad de Proyectil', 'Corta en ambas direcciones. Hace más daño cuando tienes poca vida', 'Lleva el tomo maldito a nivel 20 en menos de 10 minutos'), -- [cite: 149, 150, 151, 152]
('Guadaña', 'Cantidad de Proyectiles, Daño, Retroceso, Tamaño, Velocidad de Ataque', 'Corta en círculo a tu alrededor. Matar enemigos élite carga un ataque más fuerte.', 'Mata a Big Bob en Cementerio'); -- [cite: 154, 155, 156, 157]
Personajes
INSERT INTO Personajes (nombre, arma_inicialFK, habilidad, descripcion, obtencion) VALUES
('Zorro', (SELECT id_arma FROM Armas WHERE nombre = 'Bastón de Fuego'), 'Gana 1,5% de Suerte por nivel', 'Ágil y con una suerte sobrenatural.', 'Viene de Inicio'),
('Sir Oofie', (SELECT id_arma FROM Armas WHERE nombre = 'Espada'), 'Gana 1% de Armadura por nivel', 'Es lento, pero su armadura lo hace bastante resistento.', 'Viene de Inicio'),
('Calcio', (SELECT id_arma FROM Armas WHERE nombre = 'Hueso'), 'Tu velocidad sube con el tiempo, pero se reduce a la mitad si recibes daño. Más velocidad, más daño', 'Un necro-surfer que se marca las mejores acrobacias', 'Viene de Inicio'),
('Megachad', (SELECT id_arma FROM Armas WHERE nombre = 'Aura'), 'Flexea para evitar daño! CD-0,2s +2,5% Daño', 'Domina la mandibula más perfecta y poderosa.', 'Consigue el Tomo de Daño al nivel 7'),
('Ogro', (SELECT id_arma FROM Armas WHERE nombre = 'Hacha'), 'Gana 1,5 de Daño por nivel', 'Grande y fuerte, con las habilidades de pensar de un calcetín mojado', 'Elimina 15000 goblins'),
('Cl4nck', (SELECT id_arma FROM Armas WHERE nombre = 'Revólver'), 'Gana 1% de Probabilidad de Crítico por nivel', 'No se cómo se pronuncia su nombre', 'Completa Bosque Nivel 1'),
('Atenea', (SELECT id_arma FROM Armas WHERE nombre = 'Aegis'), 'Haz mas daño cuando tienes menos vida. Gana 2 de Espinas por nivel', 'Capitan América pero pedido de Temu(con descuento)', 'Consigue el Tomo de Espinas al nivel 9'),
('Robinetta', (SELECT id_arma FROM Armas WHERE nombre = 'Arco'), 'Gana 1% Aumento de Oro por nivel. Además aumenta un poco el Daño en función del oro total en el inventario', 'Roba a los pobres, da a los ricos.', 'Completa Bosque nivel 2'),
('Monke', (SELECT id_arma FROM Armas WHERE nombre = 'Bananarang'), 'Trepa muros y gana +2Max HP por nivel', 'Nadie sabe de dónde sacó las gafas de sol. Nadie pregunta', 'Encuentra y libera a Monke en el bosque'),
('Tony McVeloz', (SELECT id_arma FROM Armas WHERE nombre = 'Daga Inalámbrica'), 'Carga un ataque electrico moviendote por ahí. Obtén 2% Rango de Recogida por nivel', 'Tony no eligió la patineta voladora, la patineta lo eligió a él', 'Completa 2 Desafíos'),
('Arbusto', (SELECT id_arma FROM Armas WHERE nombre = 'Rifle de Francotirador'), 'Enemigos aleatorios son marcados. También ganas 1% Daño Crítico por nivel', 'Sólo un arbusto normal, nada que ver aquí', 'Encuentra y derrota a Arbusto en el bosque'),
('Birdo', (SELECT id_arma FROM Armas WHERE nombre = 'Tornado'), 'Mantén “saltar” para flotar en el aire. Además, gana 1% Daño aéreo por nivel', 'Las gafas son por tu seguridad, no por la suya', 'Mata a 100 enemigos con el arma Tornado mientras te lleva un tornado en el desierto. Compra Tornado'),
('Noelle', (SELECT id_arma FROM Armas WHERE nombre = 'Caminante de Escarcha'), 'Gana 0,75% Tamaño por nivel. Además, aumenta Daño por cada enemigo congelado actualmente', 'El Discord de Megabonk me obligó a crear este personaje', 'Usa un Microondas para duplicar Cristal de Hielo 3 veces seguidas'),
('Amog', (SELECT id_arma FROM Armas WHERE nombre = 'Frasco Venenoso'), 'Los enemigos envenandos explotan al morir, envenenado a los enemigos cercanos. Además, obtienes 1% Daño de veneno por nivel', 'Nadie sabe su verdadero nombre. Todos empezaron a llamarlo Amog, y el nunca los corrigió', 'Envenena a 50000 enemigos con Queso mohoso'),
('Hombre Espacial', (SELECT id_arma FROM Armas WHERE nombre = 'Agujero Negro'), 'Gana 1% de Aumento de XP por nivel', 'Hombre Espacial está baneado de 7 planetas y de la mayoría de las tiendas de regalos de la NASA', 'Completa 6 desafíos. Compra Agujero Negro'),
('Bandido', (SELECT id_arma FROM Armas WHERE nombre = 'Dexecutioner'), 'Gana 1% de Velocidad de Ataque por nivel', 'Un pillo astuto con espada afilada', 'Encuentra y derrota a Bandido en el Desierto'),
('Ninja', (SELECT id_arma FROM Armas WHERE nombre = 'Katana'), 'Ejecútalo a un enemigo al esquivarlo. Además, ganas 0,5% Esquivar por nivel', '¡Super veloz y escurridizo! Ni siquiera ha pagado impuestos desde 2014. ¡Está en llamas!', 'Completa Desierto Nivel 1'),
('Vlad', (SELECT id_arma FROM Armas WHERE nombre = 'Magia Sangrienta'), 'Gana 1% de Robo de Vida por nivel', 'Parece malvado, pero en realidad es un buen tipo. Siempre te saluda en el supermercado. Un tipo relajado', 'Completa Desierto Nivel 2'),
('Sir Chadwell', (SELECT id_arma FROM Armas WHERE nombre = 'Espada Corrupta'), 'Gana 1% de Dificultad por nivel', 'El novio de la esposa de Sir Oofie. Le compró una armadura nueva y le deja quedarse despierto después de las 8:30. ¡Buen tipo!', 'Completa Bosque nivel 3. Compra Espada Corrupta'),
('Cabezadado', (SELECT id_arma FROM Armas WHERE nombre = 'Dado'), '¡Tira los dados y mejora una estadística al azar cuando subas de nivel!', 'Su número favorito es el 7. ¿Quién le dice que el dado no llega tan lejos?', 'Completa 100 misiones. Compra Dado'),
('Roberto', (SELECT id_arma FROM Armas WHERE nombre = 'Guadaña'), 'Cofre gratis cada 60 seg, Bajando hasta 120 seg. También puede flotar (un poco)', 'Afirma que flota. Los científicos siguen investigando', 'Mata a Steve el Espeluznante. Compra Guadaña');


