Tomos
INSERT INTO Tomos (nombre, descripcion, estadistica_subir, obtencion) VALUES
('Tomo de Agilidad', 'Qué tan rápido te mueves', '+Velocidad de movimiento', 'Lo tienes ya desbloqueado'),
('Tomo de Tamaño', 'Cuán grandes son tus ataques, proyectiles, explosiones y más', '+Tamaño', 'Lo tienes ya desbloqueado'),
('Tomo Plateado', 'El incremento de plata te da más plata de todas las fuentes.', '+Incremento de plata', 'Lo tienes ya desbloqueado'),
('Tomo de Escudo', 'El escudo aguanta el daño en vez de perder HP antes de romperse. Se regenera rápido si no te pegan en un rato', '+Escudo', 'Lo tienes ya desbloqueado'),
('Tomo de Regeneracion', 'La regeneración de HP te aumenta la cantidad de HP que regeneras por minuto', '+Regeneración HP', 'Lo tienes ya desbloqueado'),
('Tomo de Velocidad de Proyectiles', 'La velocidad de tus proyectiles', '+Velocidad de Proyectil', 'Lo tienes ya desbloqueado'),
('Tomo de Precision', 'Probabilidad de hacer daño crítico. Con más del 100%, puedes Sobrecriticar, haciendo aun más daño', '+Probabilidad de Crítico', 'Lo tienes ya desbloqueado'),
('Tomo de Empuje', 'La distancia que empujas a los enemigos al golpearlos', '+Retroceso', 'Lo tienes ya desbloqueado'),
('Tomo de Vida', 'Máximo HP', '+Max HP', 'Lo tienes ya desbloqueado'),
('Tomo de Evasion', 'La evasión es el chance de esquivar un ataque y no recibir daño', '+Esquivar', 'Lo tienes ya desbloqueado'),
